import{c as e,S as t,j as r,m as l}from"./chunks/framework.BpLMAuoV.js";const h=JSON.parse('{"title":"R Interface","description":"","frontmatter":{},"headers":[],"relativePath":"R_interface.md","filePath":"R_interface.md","lastUpdated":null}'),i={name:"R_interface.md"};function o(s,a,n,u,c,d){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="R-Interface" tabindex="-1">R Interface <a class="header-anchor" href="#R-Interface" aria-label="Permalink to &quot;R Interface {#R-Interface}&quot;">​</a></h1><p><a href="https://mateusmaiads.github.io/rjuliabugs/" target="_blank" rel="noreferrer"><strong>RJuliaBUGS</strong></a> lets you run BUGS models from R using Julia&#39;s fast sampling algorithms.</p><p>Created by <a href="https://github.com/MateusMaiaDS" target="_blank" rel="noreferrer">Mateus Maia</a> as part of Google Summer of Code 2025.</p><h2 id="What-is-RJuliaBUGS?" tabindex="-1">What is RJuliaBUGS? <a class="header-anchor" href="#What-is-RJuliaBUGS?" aria-label="Permalink to &quot;What is RJuliaBUGS? {#What-is-RJuliaBUGS?}&quot;">​</a></h2><p>RJuliaBUGS connects R to JuliaBUGS. You write models in BUGS syntax and run them from R, but they execute using Julia&#39;s modern samplers like Hamiltonian Monte Carlo (HMC).</p><p><strong>Key benefits:</strong></p><ul><li><p>Keep your existing BUGS models</p></li><li><p>Run models faster with Julia&#39;s algorithms</p></li><li><p>Stay in R for all analysis</p></li><li><p>Works with <code>bayesplot</code>, <code>posterior</code>, <code>coda</code>, and other R packages</p></li></ul><h2 id="Related-Julia-Packages" tabindex="-1">Related Julia Packages <a class="header-anchor" href="#Related-Julia-Packages" aria-label="Permalink to &quot;Related Julia Packages {#Related-Julia-Packages}&quot;">​</a></h2><p>For R users working with Julia:</p><ul><li><p><a href="https://github.com/JuliaInterop/RCall.jl" target="_blank" rel="noreferrer"><code>RCall.jl</code></a> - Run R from Julia</p></li><li><p><a href="https://github.com/JuliaData/RData.jl" target="_blank" rel="noreferrer"><code>RData.jl</code></a> - Read/write R data files</p></li><li><p><a href="https://github.com/JuliaData/DataFrames.jl" target="_blank" rel="noreferrer"><code>DataFrames.jl</code></a> - Data manipulation (like <code>dplyr</code>)</p></li><li><p><a href="https://github.com/JuliaData/CSV.jl" target="_blank" rel="noreferrer"><code>CSV.jl</code></a> - Work with CSV files</p></li><li><p><a href="https://github.com/JuliaIO/JSON.jl" target="_blank" rel="noreferrer"><code>JSON.jl</code></a>, <a href="https://github.com/quinnj/JSON3.jl" target="_blank" rel="noreferrer"><code>JSON3.jl</code></a> - Work with JSON data</p></li></ul>',10)])])}const f=e(i,[["render",o]]);export{h as __pageData,f as default};
